example.correct_behavior:
@Test
void should_calculate_total_price_when_discount_applied() {
    // Arrange
    Product product = new Product("Laptop", Money.of(1000, "USD"));
    Discount discount = new PercentageDiscount(10);

    // Act
    Money result = product.applyDiscount(discount);

    // Assert
    assertThat(result).isEqualTo(Money.of(900, "USD"));
}
